const _hoisted_1 = /* @__PURE__ */ createStaticVNode('<h1 id="\u7B80\u4ECB" tabindex="-1">\u7B80\u4ECB <a class="header-anchor" href="#\u7B80\u4ECB" aria-hidden="true">#</a></h1><div class="tip custom-block"><p class="custom-block-title">\u4F7F\u7528\u672C\u63D2\u4EF6\u5EFA\u8BAE\u62E5\u6709\u7684\u77E5\u8BC6\u50A8\u5907</p><ul><li>\u56E0\u4E3A\u672C\u63D2\u4EF6\u662F\u57FA\u4E8E <a href="https://staging-cn.vuejs.org/" target="_blank" rel="noopener noreferrer">Vue3</a> \u6784\u5EFA \u6240\u4EE5\u5EFA\u8BAE\u60A8\u6700\u597D\u62E5\u6709 <a href="https://staging-cn.vuejs.org/" target="_blank" rel="noopener noreferrer">Vue3</a> \u7684\u4F7F\u7528\u7ECF\u9A8C\u3002</li><li>\u56E0\u4E3A\u672C\u63D2\u4EF6\u7684\u9AD8\u5EA6\u5B9A\u5236\u5316\u4F9D\u8D56\u4E8E <a href="https://developer.mozilla.org/zh-CN/docs/Web/Web_Components" target="_blank" rel="noopener noreferrer">WebComponent</a> \u6240\u4EE5\u5EFA\u8BAE\u60A8\u6700\u597D\u6709\u4E86\u89E3\u8FC7 <a href="https://developer.mozilla.org/zh-CN/docs/Web/Web_Components" target="_blank" rel="noopener noreferrer">WebComponent</a>\u7684\u6982\u5FF5\u6216\u8005\u4E86\u89E3\u8FC7 <a href="https://staging-cn.vuejs.org/" target="_blank" rel="noopener noreferrer">Vue3</a> \u7684 <a href="https://staging-cn.vuejs.org/guide/extras/web-components.html" target="_blank" rel="noopener noreferrer">defineCustomElement</a> API \u3002</li></ul></div><h2 id="\u4E3A\u4EC0\u4E48\u8981\u4F7F\u7528-xiaoyoueditor" tabindex="-1">\u4E3A\u4EC0\u4E48\u8981\u4F7F\u7528 xiaoYouEditor? <a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u8981\u4F7F\u7528-xiaoyoueditor" aria-hidden="true">#</a></h2><p>\u5982\u679C\u60A8\u6709\u6253\u7B97\u81EA\u5DF1\u624B\u5199\u4E00\u4E2A\u82B1\u91CC\u80E1\u54E8\u7684\u535A\u5BA2\u7CFB\u7EDF\u7684\u6253\u7B97,\u90A3\u4E48\u60A8\u9996\u5148\u9700\u8981\u8003\u8651\u5230\u7684\u4E00\u4E2A\u95EE\u9898\u5C31\u662F</p><p>\u201C\u5982\u4F55\u5728\u81EA\u5DF1\u7684\u535A\u5BA2\u540E\u53F0\u751F\u6210\u597D\u770B\u7684\u535A\u5BA2\u5185\u5BB9?\u201D</p><p>\u5728\u6B64\u4E4B\u524D\uFF0C\u76F8\u4FE1\u5927\u591A\u6570\u4EBA\u7684\u9009\u62E9\u4F1A\u662F \u5BCC\u6587\u672C\u7F16\u8F91\u5668 \u6216\u8005 Markdown \u7F16\u8F91\u5668,\u5BF9\u4E8E\u751F\u6210\u4E00\u4E9B\u7B80\u5355\u6734\u7D20\u7684\u5185\u5BB9\u800C\u8A00,\u5B83\u4EEC\u90FD\u662F\u5F88\u597D\u7684\u9009\u62E9\u3002</p><p>\u4F46\u968F\u7740\u4E2A\u4EBA\u5BF9\u535A\u5BA2\u7F8E\u89C2\u7A0B\u5EA6\u7684\u8981\u6C42\u63D0\u9AD8,\u5B83\u4EEC\u6216\u8BB8\u5F88\u96BE\u6EE1\u8DB3\u535A\u53CB\u4EEC\u7684\u9700\u6C42,\u81F3\u5C11\u5BF9\u4E8E\u4F5C\u8005\u6765\u8BF4\u8FD9\u662F\u4FC3\u4F7F\u6211\u5199\u8FD9\u4E2A\u63D2\u4EF6\u7684\u539F\u56E0</p><p>\u73B0\u5982\u4ECA,\u60A8\u6709\u4E86\u53E6\u4E00\u4E2A\u66F4\u597D\u7684\u9009\u62E9\u2014\u2014<b style="color:#42b883;">xiaoYouEditor</b></p><h2 id="\u5982\u4F55\u4F7F\u7528-xiaoyoueditor" tabindex="-1">\u5982\u4F55\u4F7F\u7528 xiaoYouEditor? <a class="header-anchor" href="#\u5982\u4F55\u4F7F\u7528-xiaoyoueditor" aria-hidden="true">#</a></h2><h3 id="\u9996\u5148" tabindex="-1">\u9996\u5148 <a class="header-anchor" href="#\u9996\u5148" aria-hidden="true">#</a></h3><p>\u60A8\u9700\u8981\u521B\u5EFA\u597D\u81EA\u5DF1\u6240\u9700\u7684 WebComponents,\u5982\u679C\u662F\u4F7F\u7528\u539F\u751F\u7684 WebComponent \u521B\u5EFA\u65B9\u6CD5,\u90A3\u5C5E\u5B9E\u5F88\u9EBB\u70E6\u7684,\u4E0D\u8FC7\u503C\u5F97\u5E86\u5E78\u7684\u662F\u6211\u4EEC\u6709 <a href="https://staging-cn.vuejs.org/" target="_blank" rel="noopener noreferrer">Vue3</a>\u3002</p><p><a href="https://staging-cn.vuejs.org/" target="_blank" rel="noopener noreferrer">Vue3</a> \u7684 <a href="https://staging-cn.vuejs.org/guide/extras/web-components.html" target="_blank" rel="noopener noreferrer">defineCustomElement</a> API \u5E2E\u52A9\u6211\u4EEC\u80FD\u4EE5\u5199 Vue \u5355\u6587\u4EF6\u7EC4\u4EF6\u7684\u5F62\u5F0F\u53BB\u521B\u5EFA WebComponent\uFF0C\u6BEB\u4E0D\u5938\u5F20\u7684\u8BF4\u4F60\u53EA\u8981\u4F1A\u5199 Vue \u5355\u6587\u4EF6\u7EC4\u4EF6\uFF0C\u90A3\u5C31\u80FD\u5F88\u8F7B\u677E\u7684\u521B\u5EFA\u51FA WebComponent</p><p>\u4E0D\u8FC7\u66F4\u503C\u5F97\u5E86\u5E78\u7684\u662F,\u4F5C\u8005\u63D0\u4F9B\u4E86\u4E00\u4E9B\u81EA\u7528\u7684 WebComponent,\u5982\u679C\u8FD9\u4E9B<a href="https://fuyouplus.cn" target="_blank" rel="noopener noreferrer">\u5C0F\u7EC4\u4EF6</a>\u80FD\u591F\u521A\u597D\u6EE1\u8DB3\u535A\u53CB\u4EEC\u7684\u9700\u6C42,\u90A3\u5C31\u4F1A\u7701\u4E0B\u66F4\u591A\u7684\u65F6\u95F4,\u8FD9\u4E5F\u662F\u4F5C\u8005\u6240\u671F\u671B\u7684\u3002</p><h3 id="\u5176\u6B21" tabindex="-1">\u5176\u6B21 <a class="header-anchor" href="#\u5176\u6B21" aria-hidden="true">#</a></h3><p>\u60A8\u9700\u8981\u9009\u62E9\u7F16\u8F91\u5668\u7684\u7248\u672C\u3002</p><p>\u5982\u679C\u60A8\u949F\u7231 Markdown \u7684\u5199\u6CD5,\u53EF\u4EE5\u9009\u62E9 Markdown \u7248\u7684\u7F16\u8F91\u5668\u3002</p><p>\u5982\u679C\u60A8\u60F3\u8FFD\u6C42\u6781\u81F4\u7684\u7F8E\u89C2\u548C\u5B9A\u5236\u80FD\u529B,\u53EF\u4EE5\u9009\u62E9 Custom \u7248\u7684\u7F16\u8F91\u5668\u3002</p><h2 id="custom-vs-markdown" tabindex="-1">Custom Vs Markdown <a class="header-anchor" href="#custom-vs-markdown" aria-hidden="true">#</a></h2><h3 id="markdown" tabindex="-1">Markdown <a class="header-anchor" href="#markdown" aria-hidden="true">#</a></h3><p>Markdown \u7248\u7F16\u8F91\u5668\u7531 <a href="https://github.com/markedjs/marked" target="_blank" rel="noopener noreferrer">marked</a> \u9A71\u52A8,\u5B83\u6240\u80FD\u89E3\u6790\u6E32\u67D3\u7684\u7EC4\u4EF6\u662F\u7531 <a href="https://github.com/markedjs/marked" target="_blank" rel="noopener noreferrer">marked</a> \u7684 renderer API \u51B3\u5B9A\u3002</p><p>\u5176\u5B9E Markdown \u7248\u7F16\u8F91\u5668\u4E5F\u80FD\u5B8C\u6210 WebComponent \u6E32\u67D3,\u5728\u4E00\u5B9A\u7A0B\u5EA6\u4E0A\u529F\u80FD\u4E0E Custom \u7248\u7F16\u8F91\u5668\u6709\u8026\u5408\u7684\u5730\u65B9,\u4F46\u662F Markdown \u7248\u7F16\u8F91\u5668\u65E0\u6CD5\u89E3\u6790\u5E26\u6709 slot(\u63D2\u69FD) \u7684 WebComponent,\u8FD9\u4E5F\u662F Custom \u7248\u7F16\u8F91\u5668\u51FA\u73B0\u7684\u539F\u56E0\u3002</p><h3 id="custom" tabindex="-1">Custom <a class="header-anchor" href="#custom" aria-hidden="true">#</a></h3><p>Custom \u7248\u7F16\u8F91\u5668\u5229\u7528\u6D4F\u89C8\u5668\u539F\u751F\u7684 WebComponent \u89E3\u6790\u80FD\u529B\u5168\u9762\u652F\u6301\u6240\u6709 WebComponent \u7684\u6E32\u67D3,\u7406\u8BBA\u4E0A\u53EF\u4EE5\u505A\u5230\u6240\u6709\u60A8\u80FD\u60F3\u5230\u7684\u4EFB\u4F55\u529F\u80FD!</p><p>\u4F46\u7F3A\u9677\u662F,\u4F1A\u589E\u52A0\u6D4F\u89C8\u5668\u7684\u6E32\u67D3\u5F00\u9500,\u6BD5\u7ADF\u76F8\u6BD4\u4E8E\u89E3\u6790\u51E0\u4E2A\u666E\u901A\u7684 HTML \u6807\u7B7E ,\u89E3\u6790\u4E00\u4E2A\u53D7\u5C01\u88C5\u7684 WebComponent \u4F1A\u66F4\u52A0\u590D\u6742\u4E9B\uFF0C\u4E0D\u8FC7\u5728\u6709\u865A\u62DF DOM \u7684\u52A0\u6301\u4E0B,\u8FDB\u884C\u5C40\u90E8\u66F4\u65B0,\u5176\u5B9E\u8FD9\u79CD\u6E32\u67D3\u5F00\u9500\u95EE\u9898\u51E0\u4E4E\u53EF\u4EE5\u5FFD\u7565\u4E0D\u8BA1\u3002</p><p>\u7531\u4E8E WebComponent \u6837\u5F0F\u9694\u79BB\u673A\u5236\u7684\u5B58\u5728,\u5BFC\u81F4 \u4E66\u5199\u7684 WebComponent \u5E76\u4E0D\u80FD\u9002\u7528\u5168\u5C40\u7684 css \u6837\u5F0F,\u4E0D\u8FC7\u8FD9\u4E2A\u95EE\u9898\u4E5F\u6709\u89E3\u6CD5,\u5728\u540E\u7EED\u7684\u7AE0\u8282\u4E2D\u4F1A\u4E13\u95E8\u8BB2\u89E3\u5230\u3002</p><h3 id="\u5BF9\u6BD4" tabindex="-1">\u5BF9\u6BD4 <a class="header-anchor" href="#\u5BF9\u6BD4" aria-hidden="true">#</a></h3><p>\u5176\u5B9E\u8FD9\u4E24\u4E2A\u7248\u672C\u7684\u9009\u62E9\u8BF4\u5230\u5E95\u5C31\u662F \u201C\u666E\u901A\u82B1\u54E8\u201D \u548C \u201C\u66F4\u82B1\u54E8\u201D , &quot;Markdown \u5199\u6CD5&quot; \u548C &quot;HTML \u4EE3\u7801\u5F0F\u5199\u6CD5&quot; \u4E4B\u95F4\u7684\u559C\u597D\u95EE\u9898</p><h2 id="\u5728\u7EBF\u4F53\u9A8C" tabindex="-1">\u5728\u7EBF\u4F53\u9A8C <a class="header-anchor" href="#\u5728\u7EBF\u4F53\u9A8C" aria-hidden="true">#</a></h2><p><a href="https://2383155523.github.io/xiao-you-editor-example/#/editor-custom" target="_blank" rel="noopener noreferrer">\u70B9\u6211\u5728\u7EBF\u4F53\u9A8C</a></p>', 29);
